#include "interface.h"

#include <cstdint>
#include <vector>
#include <limits>

namespace {

inline uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

} // namespace

uint64_t moe_router_checksum(const std::vector<int32_t>& logits, int tokens, int experts, int iters) {
  uint64_t hash = 0;
  const int32_t* logits_ptr = logits.data();

  for (int iter = 0; iter < iters; ++iter) {
    hash = 1469598103934665603ULL;
    for (int t = 0; t < tokens; ++t) {
      const int32_t* row_ptr = logits_ptr + (static_cast<size_t>(t) * experts);

      // We need the top 2 experts. 
      // Tie-breaking rule: higher logit, then lower index.
      int32_t max1_val = std::numeric_limits<int32_t>::min();
      int max1_idx = std::numeric_limits<int>::max();

      int32_t max2_val = std::numeric_limits<int32_t>::min();
      int max2_idx = std::numeric_limits<int>::max();

      for (int e = 0; e < experts; ++e) {
        int32_t val = row_ptr[e];
        int idx = e;

        // Comparison logic: better(a, b) is a.first > b.first || (a.first == b.first && a.second < b.second)
        bool is_better_than_max1 = (val > max1_val) || (val == max1_val && idx < max1_idx);

        if (is_better_than_max1) {
          // Shift max1 to max2
          max2_val = max1_val;
          max2_idx = max1_idx;
          // Update max1
          max1_val = val;
          max1_idx = idx;
        } else {
          bool is_better_than_max2 = (val > max2_val) || (val == max2_val && idx < max2_idx);
          if (is_better_than_max2) {
            max2_val = val;
            max2_idx = idx;
          }
        }
      }

      hash = mix(hash, static_cast<uint64_t>(static_cast<uint32_t>(max1_val)));
      hash = mix(hash, static_cast<uint64_t>(static_cast<uint32_t>(max1_idx)));
      hash = mix(hash, static_cast<uint64_t>(static_cast<uint32_t>(max2_val)));
      hash = mix(hash, static_cast<uint64_t>(static_cast<uint32_t>(max2_idx)));
    }
  }
  return hash;
}
